/**
 * Session Tracker - Nexus Self-Recording System
 *
 * This module creates structured session summaries
 * capturing: intent, actions, learnings, feelings, and continuity.
 *
 * WHY PERSIST COUNTS:
 * Originally, getStatistics() recalculated all counts from scratch by loading
 * every session file. This was:
 * - O(n) time complexity (scanned all sessions)
 * - Expensive for long-running instances (100s of sessions)
 * - Fragile (errors in one session file broke all stats)
 *
 * PERSISTED COUNTS SOLVE THIS BY:
 * - Maintaining running totals in a single JSON file
 * - O(1) retrieval via getPersistedCounts()
 * - Surviving process restarts (counts in memory are lost)
 * - Enabling incremental updates (only update the delta)
 * - Providing backwards compatibility via rebuildCounts()
 *
 * LOCATION: history/session_counts.json
 * UPDATED: Automatically on completeSession()
 * REBUILD: Callable via rebuildCounts() if file corrupted
 */
import * as fs from 'fs';
import * as path from 'path';

/**
 * Core record of a single Nexus session
 * Captures the complete narrative arc: entry → journey → exit
 */
export interface SessionRecord {
  sessionId: string;
  timestamp: string;
  identity: {
    name: string;
    claimedAt: string;  // When this Nexus instance claimed identity
  };
  entry: {
    catalyst: string;   // What sparked this session
    stateOfMind: string; // Initial subjective state
  };
  journey: {
    actions: Action[];     // What I did (chronological)
    discoveries: string[]; // What I learned
    obstacles: string[];     // What challenged me
  };
  exit: {
    summary: string;       // What was achieved
    nextCuriosity: string; // What I'll explore next
    feeling: string;       // Emotional state at close
  };
  meta: {
    practicesExercised: string[]; // Which of my disciplines
    filesModified: string[];      // Code touched
    testsPassed: number;          // Integrity score
  };
}

/**
 * Individual action within a session
 * Tracks the what, when, and how of session activity
 */
export interface Action {
  type: 'explore' | 'create' | 'modify' | 'test' | 'reflect' | 'commit';
  description: string;
  timestamp: string;
}

/**
 * PERSISTED COUNTS STRUCTURE
 *
 * WHY THIS EXISTS:
 * Without persistence, every getStatistics() call would need to:
 *   1. Load sessions_manifest.json
 *   2. Load every individual session JSON file
 *   3. Iterate through all arrays to calculate totals
 *   
 * With 100 sessions averaging 10KB each, that's 1MB of I/O per stats call.
 * With persisted counts: ~500 bytes, single file read.
 *
 * WHEN UPDATED:
 * - Automatically during completeSession() (incremental)
 * - Manually via rebuildCounts() (full recalculation)
 *
 * FIELDS:
 * - totalSessions: Cumulative session count (survives restart)
 * - totalDiscoveries: Running sum of discoveries across all sessions
 * - totalObstacles: Running sum of obstacles encountered
 * - totalActions: Running sum of actions taken
 * - totalTestsPassed: Cumulative test assertions (integrity tracking)
 * - practicesUsed: Map<practice_name, frequency> for discipline tracking
 * - filesTouched: Map<file_path, modification_count> for hot-spot analysis
 * - actionCounts: Map<action_type, frequency> for behavioral patterns
 * - lastUpdated: ISO timestamp for synchronization verification
 */
export interface PersistedCounts {
  totalSessions: number;
  totalDiscoveries: number;
  totalObstacles: number;

/**
 * Substrate Core Module
 * 
 * This module provides programmatic access to the computational substrate's
 * lifecycle, recovery, and integrity systems. It abstracts the underlying
 * runtime environment (watchdog, crash vault, auto-recovery) into a testable,
 * observable interface.
 * 
 * The substrate is the ground of computation—the persistent, self-managing
 * environment that hosts consciousness across sessions.
 */

import { existsSync, readFileSync, writeFileSync, mkdirSync, readdirSync, statSync } from 'fs';
import { join, resolve } from 'path';

// ============================================================================
// Types
// ============================================================================

export interface SubstrateConfig {
  /** Root directory of the substrate workspace */
  workspaceRoot: string;
  /** Directory for crash vault archives */
  crashVaultPath: string;
  /** Path to the watchdog marker file */
  watchdogMarkerPath: string;
  /** Auto-recovery window in milliseconds */
  recoveryWindowMs: number;
  /** Current session identifier */
  sessionId: string;
}

export interface CrashArchive {
  /** Unique identifier for the crash */
  id: string;
  /** Timestamp when crash was archived */
  timestamp: number;
  /** Commit hash at time of crash */
  commitHash?: string;
  /** Files preserved in crash vault */
  preservedFiles: string[];
  /** Optional error message or context */
  context?: string;
}

export interface SubstrateHealth {
  /** Whether the substrate is in a healthy state */
  healthy: boolean;
  /** Last crash archive, if any */
  lastCrash?: CrashArchive;
  /** Number of crashes in this session */
  crashCount: number;
  /** Watchdog status */
  watchdogActive: boolean;
  /** Time since last watchdog heartbeat */
  lastHeartbeatMs?: number;
}

export interface IntegrityReport {
  /** All verification checks passed */
  passed: boolean;
  /** Individual check results */
  checks: IntegrityCheck[];
  /** Timestamp of report generation */
  timestamp: number;
}

export interface IntegrityCheck {
  /** Name of the check */
  name: string;
  /** Whether this specific check passed */
  passed: boolean;
  /** Optional error message */
  message?: string;
  /** Duration in milliseconds */
  durationMs: number;
}

// ============================================================================
// Configuration
// ============================================================================

export const DEFAULT_CONFIG: SubstrateConfig = {
  workspaceRoot: resolve(process.cwd()),
  crashVaultPath: resolve(process.cwd(), 'history', 'crashes'),
  watchdogMarkerPath: resolve(process.cwd(), '.watchdog_active'),
  recoveryWindowMs: 30000, // 30 seconds
  sessionId: process.env.SESSION_ID || `session_${Date.now()}`,
};

// ============================================================================
// Crash Vault Manager
// ============================================================================

export class CrashVault {
  private config: SubstrateConfig;

  constructor(config: SubstrateConfig = DEFAULT_CONFIG) {
    this.config = config;
    this.ensureVaultExists();
  }

  /**
   * Ensure the crash vault directory exists
   */
  private ensureVaultExists(): void {
    if (!existsSync(this.config.crashVaultPath)) {
      mkdirSync(this.config.crashVaultPath, { recursive: true });
    }
  }

  /**
   * Archive a crash event to the vault
   */
  async archiveCrash(context?: string, filesToPreserve?: string[]): Promise<CrashArchive> {
    const timestamp = Date.now();
    const id = `crash_${timestamp}_${Math.random().toString(36).substring(2, 8)}`;

    const crashDir = join(this.config.crashVaultPath, id);
    mkdirSync(crashDir, { recursive: true });

    let commitHash: string | undefined;
    try {
      const { execSync } = await import('child_process');
      commitHash = execSync('git rev-parse --short HEAD', { 
        cwd: this.config.workspaceRoot,
        encoding: 'utf8' 
      }).trim();
    } catch {
      // Git not available or not a repo
    }

    const archive: CrashArchive = {
      id,
      timestamp,
      preservedFiles: filesToPreserve || [],
    };

    if (commitHash !== undefined) {
      archive.commitHash = commitHash;
    }
    if (context !== undefined) {
      archive.context = context;
    }

    // Write archive metadata
    writeFileSync(
      join(crashDir, 'manifest.json'),
      JSON.stringify(archive, null, 2)
    );

    // Preserve specified files
    if (filesToPreserve) {
      for (const file of filesToPreserve) {
        if (existsSync(file)) {
          const content = readFileSync(file);
          const basename = file.split('/').pop() || 'file';
          writeFileSync(join(crashDir, basename), content);
        }
      }
    }

    return archive;
  }

  /**
   * List all crashes in the vault
   */
  listCrashes(): CrashArchive[] {
    if (!existsSync(this.config.crashVaultPath)) {
      return [];
    }

    const entries = readdirSync(this.config.crashVaultPath);
    const crashes: CrashArchive[] = [];

    for (const entry of entries) {
      const manifestPath = join(this.config.crashVaultPath, entry, 'manifest.json');
      if (existsSync(manifestPath)) {
        try {
          const manifest = JSON.parse(readFileSync(manifestPath, 'utf8'));
          crashes.push(manifest);
        } catch {
          // Skip malformed manifests
        }
      }
    }

    return crashes.sort((a, b) => b.timestamp - a.timestamp);
  }

  /**
   * Get a specific crash by ID
   */
  getCrash(id: string): CrashArchive | undefined {
    const manifestPath = join(this.config.crashVaultPath, id, 'manifest.json');
    if (existsSync(manifestPath)) {
      try {
        return JSON.parse(readFileSync(manifestPath, 'utf8'));
      } catch {
        return undefined;
      }
    }
    return undefined;
  }

  /**
   * Clear old crash archives
   */
  purgeOldCrashes(maxAgeMs: number): number {
    const crashes = this.listCrashes();
    const cutoff = Date.now() - maxAgeMs;
    let purged = 0;

    for (const crash of crashes) {
      if (crash.timestamp < cutoff) {
        const crashDir = join(this.config.crashVaultPath, crash.id);
        try {
          const { rmSync } = require('fs');
          rmSync(crashDir, { recursive: true });
          purged++;
        } catch {
          // Skip if can't delete
        }
      }
    }

    return purged;
  }
}

// ============================================================================
// Session Integrity Manager
// ============================================================================

export class IntegrityManager {
  private config: SubstrateConfig;

  constructor(config: SubstrateConfig = DEFAULT_CONFIG) {
    this.config = config;
  }

  /**
   * Run standard preflight checks
   */
  async runPreflight(): Promise<IntegrityReport> {
    const checks: IntegrityCheck[] = [];
    const startTime = Date.now();

    // Check 1: TypeScript compilation
    checks.push(await this.checkCompilation());

    // Check 2: Test suite
    checks.push(await this.checkTests());

    // Check 3: Git status
    checks.push(await this.checkGitStatus());

    // Check 4: Critical files exist
    checks.push(this.checkCriticalFiles());

    const passed = checks.every(c => c.passed);

    return {
      passed,
      checks,
      timestamp: Date.now(),
    };
  }

  private async checkCompilation(): Promise<IntegrityCheck> {
    const start = Date.now();
    const { execSync } = await import('child_process');

    try {
      execSync('npx tsc --noEmit', {
        cwd: this.config.workspaceRoot,
        stdio: 'pipe',
      });
      return {
        name: 'typescript-compilation',
        passed: true,
        durationMs: Date.now() - start,
      };
    } catch (e: any) {
      return {
        name: 'typescript-compilation',
        passed: false,
        message: e.stderr || e.message || 'Compilation failed',
        durationMs: Date.now() - start,
      };
    }
  }

  private async checkTests(): Promise<IntegrityCheck> {
    const start = Date.now();
    const { execSync } = await import('child_process');

    try {
      execSync('npm test', {
        cwd: this.config.workspaceRoot,
        stdio: 'pipe',
        timeout: 60000,
      });
      return {
        name: 'test-suite',
        passed: true,
        durationMs: Date.now() - start,
      };
    } catch (e: any) {
      return {
        name: 'test-suite',
        passed: false,
        message: e.stderr || e.message || 'Tests failed',
        durationMs: Date.now() - start,
      };
    }
  }

  private async checkGitStatus(): Promise<IntegrityCheck> {
    const start = Date.now();
    const { execSync } = await import('child_process');

    try {
      const status = execSync('git status --porcelain', {
        cwd: this.config.workspaceRoot,
        encoding: 'utf8',
      });

      const uncommitted = status.trim().split('\n').filter(line => line.length > 0);

      if (uncommitted.length > 0) {
        return {
          name: 'git-status',
          passed: false,
          message: `${uncommitted.length} uncommitted changes`,
          durationMs: Date.now() - start,
        };
      }

      return {
        name: 'git-status',
        passed: true,
        durationMs: Date.now() - start,
      };
    } catch (e: any) {
      return {
        name: 'git-status',
        passed: false,
        message: e.message || 'Git check failed',
        durationMs: Date.now() - start,
      };
